import{_ as i,o as e,c as o,ae as n}from"./chunks/framework.CyZiF_rV.js";const l=JSON.parse('{"title":"KSeF API 2.0 – Przegląd kluczowych zmian","description":"","frontmatter":{},"headers":[],"relativePath":"pl/przeglad-kluczowych-zmian-ksef-api-2-0.md","filePath":"pl/przeglad-kluczowych-zmian-ksef-api-2-0.md"}'),r={name:"pl/przeglad-kluczowych-zmian-ksef-api-2-0.md"};function t(w,a,s,z,p,y){return e(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="ksef-api-2-0-–-przeglad-kluczowych-zmian" tabindex="-1">KSeF API 2.0 – Przegląd kluczowych zmian <a class="header-anchor" href="#ksef-api-2-0-–-przeglad-kluczowych-zmian" aria-label="Permalink to &quot;KSeF API 2.0 – Przegląd kluczowych zmian&quot;">​</a></h1><p>09.06.2025</p><h1 id="wprowadzenie" tabindex="-1">Wprowadzenie <a class="header-anchor" href="#wprowadzenie" aria-label="Permalink to &quot;Wprowadzenie&quot;">​</a></h1><p>Niniejszy dokument skierowany jest do zespołów technicznych i programistów mających doświadczenie z wersją 1.0 API KSeF. Zawiera przegląd najważniejszych zmian wprowadzonych w wersji 2.0, wraz z omówieniem nowych możliwości oraz praktycznych usprawnień w integracji.</p><p>Celem dokumentu jest:</p><ul><li>Wskazanie głównych różnic względem wersji 1.0</li><li>Przedstawienie korzyści z migracji na wersję 2.0</li><li>Ułatwienie przygotowania integracji do wymagań systemu wdrażanych 1 lutego 2026 r.</li></ul><hr><h2 id="dokumentacja-i-narzedzia-wspierajace-integracje-z-ksef-api-2-0" tabindex="-1">Dokumentacja i narzędzia wspierające integrację z KSeF API 2.0 <a class="header-anchor" href="#dokumentacja-i-narzedzia-wspierajace-integracje-z-ksef-api-2-0" aria-label="Permalink to &quot;Dokumentacja i narzędzia wspierające integrację z KSeF API 2.0&quot;">​</a></h2><p>Aby ułatwić przejście na nową wersję API oraz zapewnić prawidłową implementację, udostępniono zestaw oficjalnych materiałów i narzędzi wspierających integratorów:</p><p><strong>Dokumentacja techniczna (OpenAPI)</strong></p><p>Wersja 2.0 API KSeF została opisana w standardzie OpenAPI, co umożliwia zarówno łatwe przeglądanie dokumentacji przez programistów, jak i automatyczne generowanie kodu integracyjnego.</p><ul><li><p><strong>Dokumentacja</strong> (interaktywna wersja online):<br> Przeglądarkowy interfejs w formie strony WWW, prezentujący opisy metod API, modele danych, parametry oraz przykłady użycia. Przeznaczony dla programistów i analityków integracyjnych: [<a href="https://api-test.ksef.mf.gov.pl/docs/v2/index.html" target="_blank" rel="noreferrer">link</a>].</p></li><li><p><strong>Specyfikacja</strong> (plik JSON OpenAPI):<br> Surowy plik specyfikacji OpenAPI w formacie JSON, przeznaczony do wykorzystania w narzędziach automatyzujących integrację (np. generatory kodu, walidatory kontraktów API): [<a href="https://api-test.ksef.mf.gov.pl/docs/v2/openapi.json" target="_blank" rel="noreferrer">link</a>].</p></li></ul><p><strong>Oficjalna biblioteka integracyjna KSeF 2.0 Client (open source)</strong></p><p>Publiczna biblioteka udostępniona na zasadach open source, rozwijana równolegle z kolejnymi wersjami API i utrzymywana w pełnej zgodności ze specyfikacją. Stanowi rekomendowane narzędzie integracyjne, umożliwiające bieżące śledzenie zmian oraz ograniczenie ryzyka niezgodności z aktualnymi wydaniami systemu.</p><ul><li><p><strong>C#:</strong> [<a href="https://github.com/CIRFMF/ksef-client-csharp" target="_blank" rel="noreferrer">link</a>]</p></li><li><p><strong>Java:</strong> [<a href="https://github.com/CIRFMF/ksef-client-java" target="_blank" rel="noreferrer">link</a>]</p></li></ul><p><strong>Opublikowane paczki</strong></p><p>Biblioteka KSeF 2.0 Client będzie dostępna w oficjalnych repozytoriach pakietów dla najpopularniejszych języków programowania. Dla platformy .NET zostanie opublikowana jako pakiet NuGet, natomiast dla środowiska Java – jako artefakt Maven Central. Publikacja w tych repozytoriach umożliwi łatwe włączenie biblioteki do projektów oraz automatyczne śledzenie aktualizacji zgodnych z kolejnymi wersjami API.</p><p><strong>Przewodnik krok po kroku</strong></p><ul><li><strong>Przewodnik integracyjny / tutorial:</strong><br> Praktyczne instrukcje krok po kroku wraz z fragmentami kodu ilustrujące sposób korzystania z kluczowych endpointów systemu. <br>[<a href="https://github.com/CIRFMF/ksef-docs" target="_blank" rel="noreferrer">link</a>]</li></ul><h1 id="kluczowe-zmiany-w-api-2-0" tabindex="-1">Kluczowe zmiany w API 2.0 <a class="header-anchor" href="#kluczowe-zmiany-w-api-2-0" aria-label="Permalink to &quot;Kluczowe zmiany w API 2.0&quot;">​</a></h1><h2 id="nowy-model-uwierzytelniania-oparty-o-jwt" tabindex="-1">Nowy model uwierzytelniania oparty o JWT <a class="header-anchor" href="#nowy-model-uwierzytelniania-oparty-o-jwt" aria-label="Permalink to &quot;Nowy model uwierzytelniania oparty o JWT&quot;">​</a></h2><p>W wersji 1.0 uwierzytelnienie było ściśle powiązane z otwarciem sesji interaktywnej, co wprowadzało wiele ograniczeń i komplikowało integrację.</p><p>W wersji 2.0:</p><ul><li><p>Uwierzytelnianie zostało <strong>wydzielone jako osobny proces</strong>, niezależny od inicjalizacji sesji.</p></li><li><p>Wprowadzono <strong>standardowe tokeny JWT</strong>, które są wykorzystywane do autoryzacji wszystkich operacji chronionych.</p></li></ul><p>Korzyści:</p><ul><li>zgodność z praktykami rynkowymi,</li><li>możliwość wielokrotnego użycia tokena do tworzenia wielu sesji,</li><li><strong>obsługa odświeżania i unieważniania tokenów</strong>.</li></ul><p>Szczegóły procesu uwierzytelniania: [<a href="https://github.com/CIRFMF/ksef-docs/blob/main/uwierzytelnianie.md" target="_blank" rel="noreferrer">link</a>]</p><h2 id="ujednolicony-proces-inicjalizacji-dla-sesji-wsadowej-i-interaktywnej" tabindex="-1">Ujednolicony proces inicjalizacji dla sesji wsadowej i interaktywnej <a class="header-anchor" href="#ujednolicony-proces-inicjalizacji-dla-sesji-wsadowej-i-interaktywnej" aria-label="Permalink to &quot;Ujednolicony proces inicjalizacji dla sesji wsadowej i interaktywnej&quot;">​</a></h2><p>W API 2.0 proces otwierania sesji został ujednolicony i uniezależniony od trybu pracy. Po uzyskaniu tokena uwierzytelniającego, można otworzyć zarówno sesję interaktywną: POST /sessions/online, jak i wsadową: POST /sessions/batch.</p><p>W obu przypadkach przekazywany jest prosty JSON zawierający:</p><ul><li><p>kod formularza (formCode),</p></li><li><p>zaszyfrowany klucz AES do szyfrowania danych faktur (encryptionKey).</p></li></ul><p>W przypadku wysyłki wsadowej przekazywana jest również lista cząstkowych plików wraz z metadanymi wchodzących w skład paczki.</p><p>Szczegóły i przykłady użycia:</p><ul><li>wysyłka interaktywna [<a href="https://github.com/CIRFMF/ksef-docs/blob/main/sesja-interaktywna.md" target="_blank" rel="noreferrer">link</a>]</li><li>wysyłka wsadowa [<a href="https://github.com/CIRFMF/ksef-docs/blob/main/sesja-wsadowa.md" target="_blank" rel="noreferrer">link</a>]</li></ul><h2 id="obowiazkowe-szyfrowanie-wszystkich-faktur" tabindex="-1">Obowiązkowe szyfrowanie wszystkich faktur <a class="header-anchor" href="#obowiazkowe-szyfrowanie-wszystkich-faktur" aria-label="Permalink to &quot;Obowiązkowe szyfrowanie wszystkich faktur&quot;">​</a></h2><p>W wersji 1.0 szyfrowanie faktur było obowiązkowe tylko w trybie wsadowym. W trybie interaktywnym możliwość szyfrowania istniała, ale była opcjonalna.</p><p>W wersji 2.0 szyfrowanie wszystkich faktur – zarówno w trybie wsadowym, jak i interaktywnym – <strong>jest wymagane</strong>.</p><p>Każda faktura lub paczka faktur musi być zaszyfrowana lokalnie przez klienta za pomocą <strong>klucza AES</strong>, który:</p><ul><li><p>jest generowany indywidualnie dla każdej sesji,</p></li><li><p>przekazywany do systemu w trakcie otwierania sesji (encryptionKey).</p></li></ul><h2 id="szyfrowanie-asymetryczne" tabindex="-1">Szyfrowanie asymetryczne <a class="header-anchor" href="#szyfrowanie-asymetryczne" aria-label="Permalink to &quot;Szyfrowanie asymetryczne&quot;">​</a></h2><p>W wersji 2.0 wprowadzono <code>RSA-OAEP</code> z <code>SHA-256</code> i <code>MGF1-SHA256</code>. Szyfrowanie tokenów KSeF realizowane jest oddzielnym kluczem niż szyfrowanie klucza symetrycznego używanego do faktur.</p><p>Aktualne <strong>certyfikaty kluczy publicznych</strong> zwracane są przez publiczny endpoint: GET <code>/security/public-key-certificates</code></p><h2 id="spojnosc-i-nowa-konwencja-nazewnicza-w-api-2-0" tabindex="-1">Spójność i nowa konwencja nazewnicza w API 2.0 <a class="header-anchor" href="#spojnosc-i-nowa-konwencja-nazewnicza-w-api-2-0" aria-label="Permalink to &quot;Spójność i nowa konwencja nazewnicza w API 2.0&quot;">​</a></h2><p>Jedną z kluczowych zmian w KSeF API 2.0 jest ujednolicenie i uproszczenie konwencji nazewniczej zasobów, parametrów oraz modeli json. W wersji 1.0 API zawierało szereg niespójności i nadmiarowej złożoności wynikających z ewolucji systemu.</p><p>W wersji 2.0:</p><ul><li><p><strong>Endpointy</strong> zyskały czytelne, REST-owe nazewnictwo (np. sessions/online, auth/token, permissions/entities/grants).</p></li><li><p><strong>Nazwy operacji</strong> zostały uproszczone i odzwierciedlają rzeczywistą akcję (np. grant, revoke, refresh).</p></li><li><p>Uporządkowano strukturę <strong>nagłówków, parametrów i formatów danych</strong>, tak aby była spójna i zgodna z dobrymi praktykami projektowania REST API.</p></li><li><p><strong>Struktury danych</strong> są płaskie i klarowne – typy identyfikatorów i uprawnień mają jawnie określone typy enum (Nip, Pesel, Fingerprint), bez konieczności analizowania podtypów.</p></li></ul><p>Zmiany w wersji 2.0 obejmują również aktualizację nazw oraz struktur danych. Choć pełna mapa tych zmian nie została przedstawiona w niniejszym dokumencie, jest ona dostępna w dokumentacji OpenAPI v2 oraz w przykładach kodu w oficjalnym repozytorium GitHub.</p><p>Należy podkreślić, że zmiany nie mają charakteru drastycznego – <strong>nie wpływają</strong> na ogólną logikę działania systemu KSeF, a jedynie porządkują i upraszczają nazewnictwo oraz struktury, czyniąc API bardziej przejrzystym i intuicyjnym w użyciu.</p><p>Migracja do wersji 2.0 powinna być traktowana jako zmiana kontraktu integracyjnego i wymaga dostosowania implementacji po stronie systemów zewnętrznych. Zalecane jest wykorzystanie oficjalnej biblioteki integracyjnej <strong>KSeF 2.0 Client</strong>, rozwijanej i utrzymywanej przez zespół odpowiedzialny za API. Biblioteka ta implementuje wszystkie dostępne endpointy i modele danych, co znacząco ułatwia proces migracji oraz zapewnia stabilne wsparcie również w przyszłych wersjach systemu.</p><h2 id="nowy-moduł-do-zarzadzania-certyfikatami-wewnetrznymi" tabindex="-1">Nowy moduł do zarządzania certyfikatami wewnętrznymi <a class="header-anchor" href="#nowy-moduł-do-zarzadzania-certyfikatami-wewnetrznymi" aria-label="Permalink to &quot;Nowy moduł do zarządzania certyfikatami wewnętrznymi&quot;">​</a></h2><p>W ramach wersji KSeF API 2.0 wprowadzono mechanizmy umożliwiające wydawanie oraz zarządzanie wewnętrznymi <strong>certyfikatami KSeF</strong> [link do dokumentacji]. Certyfikaty będą umożliwiały uwierzytelnienie w KSeF oraz są niezbędne do wystawienia faktury w trybie offline [link do dokumentacji].</p><p>Podmioty, które pomyślnie przejdą proces uwierzytelnienia, będą mogły:</p><ul><li><p>złożyć wniosek o wydanie certyfikatu wewnętrznego KSeF, zawierającego wybrane atrybuty z certyfikatu podpisu wykorzystanego podczas uwierzytelnienia,</p></li><li><p>pobrać wystawiony certyfikat w postaci cyfrowej,</p></li><li><p>sprawdzić status złożonego wniosku o wydanie certyfikatu,</p></li><li><p>pobrać listę metadanych wydanych certyfikatów,</p></li><li><p>sprawdzić przysługujący limit liczby certyfikatów.</p></li></ul><h2 id="usprawnienie-procesu-wysyłki-wsadowej" tabindex="-1">Usprawnienie procesu wysyłki wsadowej <a class="header-anchor" href="#usprawnienie-procesu-wysyłki-wsadowej" aria-label="Permalink to &quot;Usprawnienie procesu wysyłki wsadowej&quot;">​</a></h2><p>W wersji KSeF API 2.0 wprowadzono istotne udoskonalenie w zakresie przetwarzania sesji wsadowych. Dotychczasowe rozwiązanie dostępne w API 1.0 było nieefektywne – w przypadku, gdy choćby jedna faktura w paczce zawierała błąd, odrzucana była cała przesyłka. Takie podejście skutecznie ograniczało wykorzystanie trybu wsadowego przez integratorów i powodowało znaczne utrudnienia operacyjne.</p><p>W nowym rozwiązaniu, przy przesyłaniu paczki dokumentów:</p><ul><li><p>każda faktura przetwarzana jest niezależnie,</p></li><li><p>ewentualne błędy wpływają wyłącznie na konkretne faktury, a nie na całość przesyłki,</p></li><li><p>liczba błędnych faktur jest zwracana dla statusu sesji,</p></li><li><p>dostępny jest dedykowany endpoint umożliwiający pobranie szczegółowego statusu błędnie przetworzonych faktur wraz z informacją o ewentualnym błędzie.</p></li></ul><p>Zmiana ta znacząco podnosi niezawodność i efektywność trybu wsadowego i opiera się na tym samym modelu przesyłania paczek bez ryzyka utraty całej paczki z powodu pojedynczych błędów.</p><h2 id="weryfikacja-duplikatow-faktur" tabindex="-1">Weryfikacja duplikatów faktur <a class="header-anchor" href="#weryfikacja-duplikatow-faktur" aria-label="Permalink to &quot;Weryfikacja duplikatów faktur&quot;">​</a></h2><p>Zmieniono sposób wykrywania duplikatów – obecnie sprawdzane są dane biznesowe faktury (Podmiot1:NIP, RodzajFaktury, P_2), a nie skrót pliku. Szczegóły – <a href="./faktury/weryfikacja-faktury.html">Weryfikacja duplikatów</a>.</p><h2 id="zmiana-w-module-uprawnien" tabindex="-1">Zmiana w module Uprawnień <a class="header-anchor" href="#zmiana-w-module-uprawnien" aria-label="Permalink to &quot;Zmiana w module Uprawnień&quot;">​</a></h2><p>Zmiany w module uprawnień wiążą się ze zmianą niektórych aspektów logiki ich funkcjonowania w KSeF 2.0.</p><p>W odpowiedzi na zgłaszane uwagi, w wersji 2.0 systemu wprowadzono mechanizm nadawania uprawnień w sposób pośredni, który zastępuje dotychczasową zasadę dziedziczenia uprawnień do przeglądania i wystawiania faktur. Nowy interfejs umożliwia rozdzielenie przeglądania faktur klienta (partnera) oraz możliwości wystawiania faktur w jego imieniu od przeglądania faktur oraz wystawiania faktur własnych podmiotu (np. biura rachunkowego).</p><p>Mechanizm polega na nadaniu podmiotowi przez klienta uprawnienia do przeglądania lub wystawiania faktur z włączoną specjalną opcją zezwalającą na dalsze przekazywanie tego uprawnienia przez uprawniony podmiot. Po otrzymaniu takiego uprawnienia podmiot może je nadać np. swoim pracownikom. Po wykonaniu tych czynności, pracownicy ci będą mieli możliwość obsługi wskazanego klienta w zakresie określonym przez nadane uprawnienia.</p><p>Możliwe jest również nadanie przez podmiot tzw. uprawnień generalnych, które pozwalają uprawnionemu w ten sposób pracownikowi obsługiwać wszystkich klientów podmiotu – oczywiście w takim zakresie, w jakim klienci ci uprawnili ten podmiot i przy uwzględnieniu zakresu uprawnień pracownika (do przeglądania i/lub wystawiania faktur).</p><p>Dzięki takiemu mechanizmowi, nadawanie i funkcjonowanie uprawnień do przeglądania i wystawiania faktur w ramach samego podmiotu nie są powiązane z uprawnieniami do obsługi faktur klientów. Daje to podmiotom lepsze możliwości profilowania uprawnień pracowników, niż uprzednio funkcjonujący w KSeF mechanizm dziedziczenia uprawnień. Polegał on bowiem na nadawaniu uprawnień pracownikom do przeglądania i wystawiania faktur w ramach podmiotu, a jeśli podmiot dysponował odpowiednimi uprawnieniami od klientów, to uprawnienia te automatycznie przechodziły na pracowników (były dziedziczone). W rezultacie – pracownik mógł obsługiwać klientów wyłącznie wtedy, gdy równocześnie miał prawo do przeglądania i/lub wystawiania faktur podmiotu. A to w wielu wypadkach było uprawnienie nadmiarowe, co mogło powodować problemy w organizacjach.</p><p>Ponadto w systemie wprowadzono nowy typ uprawnienia oraz nowe możliwości logowania, co umożliwia obsługę samofakturowanie przez podmioty unijne. Możliwe jest obecnie logowanie w kontekście określonym przez podmiot polski (identyfikowany przez NIP) oraz podmiot z kraju UE identyfikowany numerem VAT kraju unijnego. W tak określonym kontekście możliwe jest wystawianie przez uwierzytelnionych przedstawicieli wskazanego podmiotu unijnego faktur w trybie samofakturowania w imieniu wskazanego podmiotu polskiego.</p><p>W ramach definicji API wszystkie uprawnienia zostały uporządkowane w logiczne grupy odpowiadające poszczególnym obszarom funkcjonalnym systemu.</p><h2 id="limity-wywołan-api-rate-limiting" tabindex="-1">Limity wywołań API (rate limiting) <a class="header-anchor" href="#limity-wywołan-api-rate-limiting" aria-label="Permalink to &quot;Limity wywołań API (rate limiting)&quot;">​</a></h2><p>W wersji KSeF API 2.0 wprowadzono precyzyjny i przewidywalny mechanizm ograniczeń liczby wywołań (rate limits), który zastępuje dotychczasowe rozwiązania znane z wersji 1.0. Każdy endpoint w systemie objęty jest limitem liczby żądań w zadanych przedziałach czasowych: na sekundę, minutę, godzinę.</p><p>Zakresy i wartości limitów są:</p><ul><li>publicznie udostępniane: <a href="./limity/limity-api.html">limity API</a>,</li><li>zróżnicowane w zależności od środowiska (środowisko testowe ma limity mniej restrykcyjne niż produkcyjne),</li><li>dostosowane do charakteru operacji: <ul><li>dla endpointów chronionych – limity stosowane są per kontekst i adres IP,</li><li>dla endpointów otwartych – limity stosowane są per adres IP.</li></ul></li></ul><p>Nowy model limitów został zaprojektowany tak, aby nie ograniczać typowego testowania aplikacji integrujących się z systemem. Rozwiązanie to zapewnia większą przejrzystość, przewidywalność oraz lepszą odporność systemu, zarówno w środowiskach testowych, jak i produkcyjnych.</p><h2 id="pomocnicze-api-do-generowania-danych-testowych-srodowisko-testowe" tabindex="-1">Pomocnicze API do generowania danych testowych (środowisko testowe) <a class="header-anchor" href="#pomocnicze-api-do-generowania-danych-testowych-srodowisko-testowe" aria-label="Permalink to &quot;Pomocnicze API do generowania danych testowych (środowisko testowe)&quot;">​</a></h2><p>W środowisku testowym KSeF API 2.0 udostępnione zostanie dedykowane <strong>pomocnicze API do generowania danych testowych</strong>, umożliwiające szybkie tworzenie firm, struktur organizacyjnych i kontekstów niezbędnych do przeprowadzania testów integracyjnych.</p><p>Dzięki temu rozwiązaniu możliwe będzie m.in.:</p><ul><li><p><strong>symulowanie założenia nowego podmiotu gospodarczego</strong>,</p></li><li><p><strong>symulacja nadania uprawnień przez ZAW-FA</strong>,</p></li><li><p><strong>tworzenie jednostek w ramach struktury JST</strong>,</p></li><li><p>tworzenie podatkowych <strong>grup VAT</strong> (GVAT) wraz z podmiotami powiązanymi,</p></li><li><p><strong>definiowanie organów egzekucyjnych</strong> <strong>i komorników sądowych</strong>.</p></li></ul><p>Standardowo, proces rejestracji firm i nadania uprawnień dla rzeczywistych podmiotów w środowisku produkcyjnym wymaga działań formalnych (np. wizyty w urzędzie skarbowym). W środowisku testowym takie dane nie istnieją. Dlatego <strong>pomocnicze API jest niezbędnym narzędziem</strong>, umożliwiającym integratorom samodzielne tworzenie podmiotów testowych, na których mogą swobodnie realizować i weryfikować pełne scenariusze działania swoich aplikacji.</p>',78)])])}const d=i(r,[["render",t]]);export{l as __pageData,d as default};
